bool myConstantPropagation(Function &Foo) {
  bool modified = false;
  if (Foo.empty()) return false;

  for (BasicBlock &BB : Foo) {
    for (auto it = BB.begin(); it != BB.end();) {
      Instruction &I = *it++;
      if (auto *BinOp = dyn_cast<BinaryOperator>(&I)) {
        if (auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0))) {
          if (auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1))) {
            Constant *Res = ConstantFoldBinaryOp(BinOp, LHS, RHS);
            if (Res) {
              BinOp.replaceAllUsesWith(Res);
              BinOp.eraseFromParent();
              modified = true;
            }
          }
        }
      }
    }
  }
  return modified;
}

